import{_ as a,o as t,c as i,a2 as o}from"./chunks/framework.Ke-G87zD.js";const u=JSON.parse('{"title":"Releasing ADP","description":"","frontmatter":{},"headers":[],"relativePath":"agent-data-plane/releasing.md","filePath":"agent-data-plane/releasing.md","lastUpdated":1782938424000}'),s={name:"agent-data-plane/releasing.md"};function n(l,e,r,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="releasing-adp" tabindex="-1">Releasing ADP <a class="header-anchor" href="#releasing-adp" aria-label="Permalink to &quot;Releasing ADP&quot;">​</a></h1><p>This page covers the overall release process for Agent Data Plane, including the steps required to create a new release, as well as the technical details around how we determine the version of the release, what metadata is collected/generated, and more.</p><h2 id="high-level-overview" tabindex="-1">High-level overview <a class="header-anchor" href="#high-level-overview" aria-label="Permalink to &quot;High-level overview&quot;">​</a></h2><p>The release process for ADP roughly looks like this:</p><ul><li>create a GitHub release, which tags <code>main</code> at a particular point</li><li>creation of the Git tag triggers a CI pipeline that additionally unlocks jobs to publish release artifacts</li><li>the additional CI jobs, once manually triggered, will publish ADP container images to various public container image registries</li><li>bump the version of ADP to the next development version</li><li>post a release announcement in the <code>#agent-data-plane</code> Slack channel</li></ul><h2 id="quick-steps" tabindex="-1">Quick steps <a class="header-anchor" href="#quick-steps" aria-label="Permalink to &quot;Quick steps&quot;">​</a></h2><ul><li>Ensure that <code>main</code> is up-to-date with all of the intended changes that should be present, and that CI tests are passing cleanly (this will get checked in the actual release CI pipeline, but easier to catch problems early)</li><li>Go to the <a href="https://github.com/DataDog/saluki/releases" target="_blank" rel="noreferrer">Releases</a> page on GitHub and click the <code>Draft a new release</code> button.</li><li>Fill in the appropriate Git tag (see <a href="#determining-the-version">&quot;Determining the version&quot;</a> below) and click <code>Create new tag ... on publish</code>.</li><li>Leave <code>Previous tag</code> at <code>auto</code>, and change <code>Release title</code> to <code>Agent Data Plane &lt;version&gt;</code>, where <code>&lt;version&gt;</code> is the Git tag being created. (for example, <code>Agent Data Plane 0.2.0</code>)</li><li>Click the <code>Generate release notes</code> to automatically populate the relevant changes since the last release.</li><li>If there are any additional notes that should be included, add a new section, called <code>Additional Notes</code>, at the top of the release notes. (above the auto-generated <code>What&#39;s Changed</code> section)</li><li>Click <code>Publish release</code>.</li><li>Go to the <a href="https://gitlab.ddbuild.io/DataDog/saluki/-/pipelines" target="_blank" rel="noreferrer">GitLab CI pipelines dashboard</a> for the repository and find the pipeline that was triggered for the newly created Git tag. It may take a minute or two for the repository sync and pipeline creation to occur.</li><li>The pipeline should progress through the <code>test</code>, <code>build</code>, <code>correctness</code>, and <code>release</code> stages without issue.</li><li>Once all stages have completed, the <code>release</code> stage will have a number of blocked jobs: standalone image publishing, release tarball publishing, and so on. These jobs perform any necessary final packaging and publish ADP release artifacts, in their various forms, to the relevant container registries and object storage. They <em>must</em> be triggered manually.</li><li>Once triggered, they should run to completion.</li><li>Once complete, you should be able to navigate to a public container image registry that we use, such as <a href="https://hub.docker.com/r/datadog/agent-data-plane/tags" target="_blank" rel="noreferrer">Docker Hub</a>, and find the resulting images: if the tag was <code>0.2.0</code>, you should be able to see a recently published image with a tag that looks like <code>0.2.0</code> and <code>0.2.0-fips</code>.</li><li>Post a release announcement in the <code>#agent-data-plane</code> Slack channel in the following format:<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent Data Plane vX.Y.Z: &lt;link to GitHub release&gt;</span></span>
<span class="line"><span>CI pipeline: &lt;link to GitLab CI pipeline for the git tag&gt;</span></span></code></pre></div></li></ul><h2 id="determining-the-version" tabindex="-1">Determining the version <a class="header-anchor" href="#determining-the-version" aria-label="Permalink to &quot;Determining the version&quot;">​</a></h2><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Git tags <strong>must</strong> be in the format of <code>X.Y.Z</code>.</p></div><p>For ADP, we use the Git tag to drive the versioning of the release artifacts themselves, but the tag is expected to match the version of the <code>agent-data-plane</code> crate. This is due to how we use the version of the <code>agent-data-plane</code> crate itself for embedding static metadata in the ADP binaries. The version of the ADP binary can be found in the <code>bin/agent-data-plane/Cargo.toml</code> file, under the <code>version</code> field.</p><h3 id="determining-the-next-version" tabindex="-1">Determining the <em>next</em> version <a class="header-anchor" href="#determining-the-next-version" aria-label="Permalink to &quot;Determining the _next_ version&quot;">​</a></h3><p>Normally, a CI job will run to bump the patch release of ADP after the Git tag is generated for the current release. In some cases, we may need to bump the minor or major version due to major/breaking changes. When deciding what minor/major version to bump to, we follow the <a href="https://semver.org/" target="_blank" rel="noreferrer">Semantic Versioning</a> specification. This means, in a nutshell:</p><ul><li>prior to v1.0.0: <ul><li>breaking changes are indicated by incrementing the minor version</li><li>new features and bug fixes are generally indicated by incrementing the patch version</li><li>if there are enough new features/bug fixes, we may instead opt to increment the minor version just for simplicity</li></ul></li><li>after v1.0.0: <ul><li>breaking changes are indicated by incrementing the major version (this should generally never happen after v1)</li><li>new features are indicated by incrementing the minor version</li><li>bug fixes are indicated by incrementing the patch version</li></ul></li></ul><h2 id="build-metadata" tabindex="-1">Build metadata <a class="header-anchor" href="#build-metadata" aria-label="Permalink to &quot;Build metadata&quot;">​</a></h2><p>We calculate a number of values that are used to populate what we call <em>build metadata</em>, which is information passed in during the build process and is used to drive a number of behaviors:</p><ul><li>outputting the version of ADP, when it was built, the build architecture, etc, as a log at startup</li><li>special constant identifiers that are used to populate things like HTTP request headers (user agent, etc)</li></ul><p>This build metadata is calculated with a Make target—<code>emit-build-metadata</code>—which populates it during local builds or regular CI builds. The relevant build arguments are all prefixed with <code>APP_</code> and are as follows:</p><ul><li><code>APP_FULL_NAME</code>: the full name of the application (hard-coded to <code>agent-data-plane</code>)</li><li><code>APP_SHORT_NAME</code>: the short name of the application (hard-coded to <code>data-plane</code>)</li><li><code>APP_IDENTIFIER</code>: a short identifier for the application (hard-coded to <code>adp</code>)</li><li><code>APP_VERSION</code>: the version of the application (set to <code>version</code> field in <code>bin/agent-data-plane/Cargo.toml</code>)</li><li><code>APP_BUILD_DATE</code>: the date the build was performed (set to the creation time of the GitLab CI pipeline)</li></ul><p>This build metadata shouldn&#39;t need to be manually changed on a per-release basis, and so this section is mostly informational and not relevant to the release process itself.</p><h2 id="software-bill-of-materials-sbom" tabindex="-1">Software bill of materials (SBOM) <a class="header-anchor" href="#software-bill-of-materials-sbom" aria-label="Permalink to &quot;Software bill of materials (SBOM)&quot;">​</a></h2><p>Every ADP binary produced in CI -- both the internal/dev images built on each pipeline and the published release artifacts -- embeds a software bill of materials (SBOM): a compact JSON record of the exact dependency tree the binary was built from. This lets you audit a shipped binary for vulnerable dependencies without access to its source tree or <code>Cargo.lock</code>.</p><p>The SBOM is produced by <a href="https://github.com/rust-secure-code/cargo-auditable" target="_blank" rel="noreferrer"><code>cargo-auditable</code></a>, used during CI to build ADP in a way that captures the exact dependencies used, both the name and version. The dependency list lives in a dedicated linker section of the binary, adds only a few kilobytes, survives stripping, and is reproducible-build-safe (no timestamps; sorted output). It is also natively supported by tools like <code>cargo-audit</code> and Trivy, making it possible for customers to audit ADP binaries for vulnerable dependencies without access to the source code or bespoke tooling.</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Local developer builds (<code>make build-adp</code>, <code>make build-adp-host</code>, <code>make build-adp-image</code>) do <strong>not</strong> embed an SBOM. The wrapper is enabled only in CI, where GitLab sets <code>CI=true</code> (host builds) or the build passes <code>USE_CARGO_AUDITABLE=true</code> (Linux Docker builds). The SBOM only matters for artifacts we ship, so local builds stay on plain <code>cargo build</code>.</p></div><p>To inspect the SBOM embedded in a binary, use <code>rust-audit-info</code> or <code>cargo-audit</code>&#39;s <code>bin</code> subcommand:</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Print the embedded dependency tree as JSON.</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rust-audit-info</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/local/bin/agent-data-plane</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Or scan it directly against the RustSec advisory database.</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> audit</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/local/bin/agent-data-plane</span></span></code></pre></div><p>The <code>cargo-auditable</code> version is pinned in the <code>Makefile</code> (the <code>CARGO_TOOL_VERSION_cargo-auditable</code> variable), which the host and Linux Docker builds share. The Windows build pins the same version and its archive checksum separately in <code>ci/tooling/windows-build-adp.ps1</code>; bump both together.</p>`,26)])])}const g=a(s,[["render",n]]);export{u as __pageData,g as default};
